Here's a modern MSTest test class using both `[DataRow]` and `[DynamicData]` with ValueTuples:

```csharp
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "Two items, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.1, DisplayName = "Negative price throws")]
    public void CalculateTotal_NegativePrice_Throws(double price, int qty, double tax)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)price, qty, (decimal)tax));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.1, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeQuantity_Throws(double price, int qty, double tax)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)price, qty, (decimal)tax));
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for complex/decimal data ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (99.99m, 50m, 49.995m),
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount throws")]
    [DataRow(101.0, DisplayName = "Over 100% discount throws")]
    public void ApplyDiscount_InvalidPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }
}
```

**Key patterns used:**

- **`[DataRow]`** — inline values for simple numeric cases (`double` params since `DataRow` doesn't support `decimal` literals)
- **`[DynamicData]` with ValueTuples** — type-safe `decimal` data without `object[]` boxing (MSTest 3.7+)
- **`sealed` class**, constructor init, AAA pattern
- **`Assert.ThrowsExactly`** instead of `[ExpectedException]` for exception tests
- **`DisplayName`** for readable test explorer output

